        incisos: [{"id":"lce26:art-6-inc-I","numero":"I","texto":"prestar orientação jurídica e exercer a defesa dos necessitados, em todos os graus;","alineas":[]},{"id":"lce26:art-6-inc-II","numero":"II","texto":"promover, prioritariamente, a solução extrajudicial dos litígios, visando à composição entre as pessoas em conflito de interesses, por meio de mediação, conciliação, arbitragem e demais técnicas de composição e administração de conflitos;","alineas":[]},{"id":"lce26:art-6-inc-III","numero":"III","texto":"promover a difusão e a conscientização dos direitos humanos, da cidadania e do ordenamento jurídico;","alineas":[]},{"id":"lce26:art-6-inc-IV","numero":"IV","texto":"prestar atendimento interdisciplinar, por meio de órgãos ou de servidores de suas Carreiras de apoio para o exercício de suas atribuições;","alineas":[]},{"id":"lce26:art-6-inc-V","numero":"V","texto":"exercer, mediante o recebimento dos autos com vista, a ampla defesa e o contraditório em favor de pessoas naturais e jurídicas, em processos administrativos e judiciais, perante todos os órgãos e em todas as instâncias, ordinárias ou extraordinárias, utilizando todas as medidas capazes de propiciar a adequada e efetiva defesa de seus interesses;","alineas":[]},{"id":"lce26:art-6-inc-VI","numero":"VI","texto":"representar aos sistemas internacionais de proteção dos direitos humanos, postulando perante seus órgãos;","alineas":[]},{"id":"lce26:art-6-inc-VII","numero":"VII","texto":"promover ação civil pública e todas as espécies de ações capazes de propiciar a adequada tutela dos direitos difusos, coletivos ou individuais homogêneos quando o resultado da demanda puder beneficiar grupo de pessoas hipossuficientes;","alineas":[]},{"id":"lce26:art-6-inc-VIII","numero":"VIII","texto":"exercer a defesa dos direitos e interesses individuais, difusos, coletivos e individuais homogêneos e dos direitos do consumidor, na forma do inciso LXXIV do art. 5º da Constituição Federal;","alineas":[]},{"id":"lce26:art-6-inc-IX","numero":"IX","texto":"impetrar habeas corpus, mandado de injunção, habeas data e mandado de segurança ou qualquer outra ação em defesa das funções institucionais e prerrogativas de seus órgãos de execução;","alineas":[]},{"id":"lce26:art-6-inc-X","numero":"X","texto":"promover a mais ampla defesa dos direitos fundamentais dos necessitados, abrangendo seus direitos individuais, coletivos, sociais, econômicos, culturais e ambientais, sendo admissíveis todas as espécies de ações capazes de propiciar sua adequada e efetiva tutela;","alineas":[]},{"id":"lce26:art-6-inc-XI","numero":"XI","texto":"exercer a defesa dos interesses individuais e coletivos da criança e do adolescente, do idoso, da pessoa portadora de necessidades especiais, da mulher vítima de violência doméstica e familiar e de outros grupos sociais vulneráveis que mereçam proteção especial do Estado;","alineas":[]},{"id":"lce26:art-6-inc-XII","numero":"XII","texto":"acompanhar inquérito policial, inclusive com a comunicação imediata da prisão em flagrante pela autoridade policial, quando o preso não constituir advogado;","alineas":[]},{"id":"lce26:art-6-inc-XIII","numero":"XIII","texto":"patrocinar os direitos e interesses do consumidor lesado;","alineas":[]},{"id":"lce26:art-6-inc-XIV","numero":"XIV","texto":"atuar nos estabelecimentos policiais, penitenciários e de internação de adolescentes, visando a assegurar às pessoas, sob quaisquer circunstâncias, o exercício pleno de seus direitos e garantias fundamentais;","alineas":[]},{"id":"lce26:art-6-inc-XV","numero":"XV","texto":"atuar na preservação e reparação dos direitos de pessoas vítimas de tortura, abusos sexuais, discriminação ou qualquer outra forma de opressão ou violência, propiciando o acompanhamento e o atendimento interdisciplinar das vítimas;","alineas":[]},{"id":"lce26:art-6-inc-XVI","numero":"XVI","texto":"atuar nos Juizados Especiais;","alineas":[]},{"id":"lce26:art-6-inc-XVII","numero":"XVII","texto":"atuar junto aos órgãos de deliberação coletiva da Administração Pública e junto aos conselhos de políticas públicas;","alineas":[]},{"id":"lce26:art-6-inc-XVIII","numero":"XVIII","texto":"participar de programas de orientação e informação de direitos à população e aos servidores públicos;","alineas":[]},{"id":"lce26:art-6-inc-XIX","numero":"XIX","texto":"participar, quando tiver assento, de comissões interdisciplinares destinadas a assuntos relacionados às funções institucionais;","alineas":[]},{"id":"lce26:art-6-inc-XX","numero":"XX","texto":"promover a edição de súmulas da jurisprudência predominante dos tribunais;","alineas":[]},{"id":"lce26:art-6-inc-XXI","numero":"XXI","texto":"convocar audiências públicas para discutir matérias relacionadas às suas funções institucionais;","alineas":[]},{"id":"lce26:art-6-inc-XXII","numero":"XXII","texto":"propor ação civil pública para tutela do meio ambiente e do patrimônio público e social;","alineas":[]},{"id":"lce26:art-6-inc-XXIII","numero":"XXIII","texto":"exercer a curadoria especial nos casos previstos em lei.","alineas":[]}],
