        paragrafos: [],
        incisos: [{"id":"lce26:art-62-inc-I","numero":"I","texto":"Defensor Público de 1ª Classe;","alineas":[]},{"id":"lce26:art-62-inc-II","numero":"II","texto":"Defensor Público de 2ª Classe;","alineas":[]},{"id":"lce26:art-62-inc-III","numero":"III","texto":"Defensor Público Substituto.","alineas":[]}],
