        id: "lce26:art-99",
        numero: "99",
        caput: "São prerrogativas dos membros da Defensoria Pública do Estado:",
        paragrafos: [],
        incisos: [{"id":"lce26:art-99-inc-I","numero":"I","texto":"receber intimação pessoal em qualquer processo e grau de jurisdição, contando-se-lhes em dobro todos os prazos;","alineas":[]},{"id":"lce26:art-99-inc-II","numero":"II","texto":"não ser preso senão por ordem judicial escrita, salvo em flagrante, caso em que a autoridade fará imediata comunicação ao Defensor Público Geral;","alineas":[]},{"id":"lce26:art-99-inc-III","numero":"III","texto":"ser recolhido a prisão especial ou a sala especial de Estado-Maior, com direito a privacidade e à instalação condigna, quando sujeito a prisão antes de decisão judicial transitada em julgado;","alineas":[]},{"id":"lce26:art-99-inc-IV","numero":"IV","texto":"usar vestes talares e as insígnias privativas da Defensoria Pública;","alineas":[]},{"id":"lce26:art-99-inc-V","numero":"V","texto":"ter vista pessoal dos processos fora dos cartórios e secretarias;","alineas":[]},{"id":"lce26:art-99-inc-VI","numero":"VI","texto":"comunicar-se, pessoal e reservadamente, com seus assistidos, ainda quando estes se acharem presos ou detidos, mesmo incomunicáveis;","alineas":[]},{"id":"lce26:art-99-inc-VII","numero":"VII","texto":"ter acesso a qualquer repartição pública, estabelecimento público ou sob administração pública, diretamente relacionados à função institucional, independentemente de prévio agendamento;","alineas":[]},{"id":"lce26:art-99-inc-VIII","numero":"VIII","texto":"examinar, em qualquer repartição policial, os autos de flagrante, de inquérito e de qualquer outro procedimento investigativo;","alineas":[]},{"id":"lce26:art-99-inc-IX","numero":"IX","texto":"manifestar-se em autos administrativos ou judiciais por meio de cota;","alineas":[]},{"id":"lce26:art-99-inc-X","numero":"X","texto":"requisitar de autoridade pública e de seus agentes, certidões, exames, perícias, vistorias, diligências, processos, documentos, informações, esclarecimentos e providências;","alineas":[]},{"id":"lce26:art-99-inc-XI","numero":"XI","texto":"ter o mesmo tratamento protocolar reservado aos Magistrados e membros do Ministério Público;","alineas":[]},{"id":"lce26:art-99-inc-XII","numero":"XII","texto":"sentar-se no mesmo plano do Ministério Público;","alineas":[]},{"id":"lce26:art-99-inc-XIII","numero":"XIII","texto":"deixar de patrocinar ação, quando ela for manifestamente incabível ou inconveniente aos interesses da parte, comunicando o fato ao Defensor Público Geral, com as razões de seu proceder;","alineas":[]},{"id":"lce26:art-99-inc-XIV","numero":"XIV","texto":"ter livre acesso e trânsito em estabelecimentos públicos ou sob administração pública para o exercício de suas funções.","alineas":[]}],
