        caput: "São deveres dos membros da Defensoria Pública:",
        paragrafos: [],
        incisos: [{"id":"lce26:art-122-inc-I","numero":"I","texto":"residir na localidade onde exercem suas funções;","alineas":[]},{"id":"lce26:art-122-inc-II","numero":"II","texto":"desempenhar, com zelo e presteza, os serviços a seu cargo;","alineas":[]},{"id":"lce26:art-122-inc-III","numero":"III","texto":"representar ao Defensor Público Geral sobre as irregularidades de que tiver ciência em razão do cargo;","alineas":[]},{"id":"lce26:art-122-inc-IV","numero":"IV","texto":"adotar as providências cabíveis em face das irregularidades de que tiver ciência, ou comunicar à autoridade competente para que o faça;","alineas":[]},{"id":"lce26:art-122-inc-V","numero":"V","texto":"atender ao expediente forense e participar dos atos judiciais, quando for obrigatória a sua presença;","alineas":[]},{"id":"lce26:art-122-inc-VI","numero":"VI","texto":"declarar-se impedido ou suspeito, nos termos da lei;","alineas":[]},{"id":"lce26:art-122-inc-VII","numero":"VII","texto":"interpor os recursos cabíveis para qualquer instância ou tribunal e promover revisão criminal, sempre que encontrar fundamentos na lei e na jurisprudência;","alineas":[]},{"id":"lce26:art-122-inc-VIII","numero":"VIII","texto":"prestar informações quando solicitadas pelos órgãos da Defensoria Pública;","alineas":[]},{"id":"lce26:art-122-inc-IX","numero":"IX","texto":"manter conduta compatível com o exercício do cargo;","alineas":[]},{"id":"lce26:art-122-inc-X","numero":"X","texto":"guardar segredo sobre fato de que tenha ciência em razão do cargo;","alineas":[]},{"id":"lce26:art-122-inc-XI","numero":"XI","texto":"frequentar os cursos de aperfeiçoamento promovidos pela Escola Superior da Defensoria Pública;","alineas":[]},{"id":"lce26:art-122-inc-XII","numero":"XII","texto":"prestar assistência aos necessitados, quando comprovada a insuficiência de recursos;","alineas":[]},{"id":"lce26:art-122-inc-XIII","numero":"XIII","texto":"tratar com urbanidade as partes, testemunhas, funcionários e auxiliares da Justiça;","alineas":[]},{"id":"lce26:art-122-inc-XIV","numero":"XIV","texto":"desempenhar com zelo e probidade as funções do cargo;","alineas":[]},{"id":"lce26:art-122-inc-XV","numero":"XV","texto":"cumprir as ordens de serviço e as determinações superiores, salvo quando manifestamente ilegais;","alineas":[]},{"id":"lce26:art-122-inc-XVI","numero":"XVI","texto":"submeter-se a inspeção pela Corregedoria Geral.","alineas":[]}],
